import{_ as l,C as r,o as c,c as d,j as e,a as h,E as a,w as n,aa as g}from"./chunks/framework.DHLMKRb3.js";const _=JSON.parse('{"title":"Debugging The World","description":"","frontmatter":{},"headers":[],"relativePath":"guide/debugging-the-world.md","filePath":"guide/debugging-the-world.md","lastUpdated":1776563507000}'),u={name:"guide/debugging-the-world.md"},p=["src"],m=["src"];function b(o,t,f,y,w,T){const i=r("PluginTabsTab"),s=r("PluginTabs");return c(),d("div",null,[t[0]||(t[0]=e("h1",{id:"debugging-the-world",tabindex:"-1"},[h("Debugging The World "),e("a",{class:"header-anchor",href:"#debugging-the-world","aria-label":'Permalink to "Debugging The World"'},"​")],-1)),t[1]||(t[1]=e("p",null,"Consul Scriptum provides a way to inspect game objects directly in the world without writing a single line of code. By toggling debug mode, you will see the available Lua data for settlements, characters, and units as you interact with them.",-1)),a(s,{sharedStateKey:"game"},{default:n(()=>[a(i,{label:"Attila"},{default:n(()=>[e("p",null,[e("video",{src:o.$withBase("/videos/attila_debugging.mp4"),"data-title":"Killing Multiple Characters","data-game":"Attila",autoplay:"",loop:"",muted:"",playsinline:""},null,8,p)])]),_:1}),a(i,{label:"Rome II"},{default:n(()=>[e("p",null,[e("video",{src:o.$withBase("/videos/rome2_debugging.mp4"),"data-title":"Transferring Settlement & Killing Character","data-game":"Rome II",autoplay:"",loop:"",muted:"",playsinline:""},null,8,m)])]),_:1})]),_:1}),t[2]||(t[2]=g('<h2 id="the-debug-command" tabindex="-1">The /debug Command <a class="header-anchor" href="#the-debug-command" aria-label="Permalink to &quot;The /debug Command&quot;">​</a></h2><p>To start debugging, simply type the following command in the console:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/debug</span></span></code></pre></div><p>This is a toggle command. Type it again to disable debug mode.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Once debug mode is active, the console will automatically update and clear itself to show information based on your actions in the game world.</p><h3 id="inspecting-settlements-and-characters" tabindex="-1">Inspecting Settlements and Characters <a class="header-anchor" href="#inspecting-settlements-and-characters" aria-label="Permalink to &quot;Inspecting Settlements and Characters&quot;">​</a></h3><p>Simply click on any <strong>Settlement</strong> or <strong>Character</strong> (General/Agent) on the campaign map. The console will print the script interface data for that object, including its name, region, faction, and other internal properties.</p><h3 id="inspecting-factions-and-settlements" tabindex="-1">Inspecting Factions and Settlements <a class="header-anchor" href="#inspecting-factions-and-settlements" aria-label="Permalink to &quot;Inspecting Factions and Settlements&quot;">​</a></h3><p>Open the <strong>Diplomacy View</strong> or <strong>Strategic Map</strong> and click any faction or settlement on the map.</p><h3 id="inspecting-units" tabindex="-1">Inspecting Units <a class="header-anchor" href="#inspecting-units" aria-label="Permalink to &quot;Inspecting Units&quot;">​</a></h3><p>If you have a character selected, you can <strong>hover your mouse</strong> over any unit card in their army. The console will display details about that unit, such as its unit key, category, and class.</p><p>This also works for:</p><ul><li><strong>Recruitable units</strong> in the recruitment panel.</li><li><strong>Mercenary units</strong> in the mercenary pool.</li><li><strong>Units</strong> in the Custom Battles main menu.</li></ul><h3 id="console-output-mirroring" tabindex="-1">Console Output Mirroring <a class="header-anchor" href="#console-output-mirroring" aria-label="Permalink to &quot;Console Output Mirroring&quot;">​</a></h3><p>The information printed to the console during debug mode (and all other console output) is also mirrored to a local file:</p><p><strong><code>consul.output</code></strong> (located in your game root folder)</p><p>This is particularly useful if you want to copy large amounts of data or keep a history of your inspections for later reference.</p><h2 id="technical-overview" tabindex="-1">Technical Overview <a class="header-anchor" href="#technical-overview" aria-label="Permalink to &quot;Technical Overview&quot;">​</a></h2><p>Under the hood, Consul Scriptum listens for UI click events. When an element is clicked, the script parses the UI element to extract the string identifier representing the object (such as a faction, settlement, or character). It then queries the global <code>GAME</code> object to retrieve the corresponding script interface. Once the object is found, the system dynamically iterates through and calls its available methods to gather data, which is then formatted and printed directly to the console.</p>',20))])}const k=l(u,[["render",b]]);export{_ as __pageData,k as default};
